+public class ExtractiveSummarizer : IDocumentSummarizer
+{
+    private const int MaxSummarySentences = 3;
+
+    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
+    {
+        "the", "a", "an", "is", "are", "was", "were", "be", "been", "being",
+        "have", "has", "had", "do", "does", "did", "will", "would", "shall",
+        "should", "may", "might", "must", "can", "could", "to", "of", "in",
+        "for", "on", "with", "at", "by", "from", "as", "into", "through",
+        "during", "before", "after", "and", "but", "or", "nor", "not", "so",
+        "yet", "both", "either", "neither", "each", "every", "all", "any",
+        "few", "more", "most", "other", "some", "such", "no", "only", "own",
+        "same", "than", "too", "very", "just", "because", "if", "when",
+        "that", "this", "it", "its", "he", "she", "they", "them", "his",
+        "her", "their", "we", "our", "you", "your", "i", "me", "my"
+    };
+
+    public string Summarize(string documentText)
+    {
+        var sentences = SplitIntoSentences(documentText);
+
+        if (sentences.Count <= MaxSummarySentences)
+            return string.Join(" ", sentences);
+
+        var wordFrequencies = ComputeWordFrequencies(sentences);
+        var scoredSentences = sentences
+            .Select((sentence, index) => (Sentence: sentence, Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
+            .OrderByDescending(s => s.Score)
+            .Take(MaxSummarySentences)
+            .OrderBy(s => s.Index) // preserve original order
+            .Select(s => s.Sentence);
+
+        return string.Join(" ", scoredSentences);
+    }
+
+    private static List<string> SplitIntoSentences(string text)
+    {
+        return text
+            .Split(['.', '!', '?'], StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
+            .Where(s => s.Length > 0)
+            .Select(s => s + ".")
+            .ToList();
+    }
+
+    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
+    {
+        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+
